import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const efLessonsB1: Lesson[] = [
  createLesson('g1-ef-b1-l1', 'L1: EF no Ensino Médio — Corpo, Cultura e Movimento', 'educacao_fisica', 'Educação Física no Ensino Médio: mais do que praticar esportes. A EF como componente curricular que trata da cultura corporal de movimento. O que é cultura corporal: esportes, dança, lutas, ginástica, jogos — práticas corporais com significado cultural e histórico. Relação entre corpo, sociedade e identidade. A EF e a saúde integral (física, mental, social). O ENEM e a EF: cultura corporal, saúde, lazer, inclusão. Levantamento: quais práticas corporais fazem parte da vida dos alunos?', ['Quais práticas corporais você realiza na sua vida? Como elas se relacionam com sua identidade e cultura?', 'Por que a Educação Física é componente curricular obrigatório? Qual sua relevância além da atividade física?']),
  createLesson('g1-ef-b1-l2', 'L2: Corpo e Saúde — Conceitos Fundamentais', 'educacao_fisica', 'Saúde como conceito amplo (OMS): "estado de completo bem-estar físico, mental e social — não apenas ausência de doenças." Determinantes da saúde: alimentação, atividade física, saneamento, moradia, educação, renda, ambiente. Saúde e desigualdade: o acesso à saúde é desigual no Brasil. Atividade física e saúde: benefícios comprovados (cardiovascular, muscular, mental, imunológico). Sedentarismo: dados alarmantes entre adolescentes brasileiros (IBGE 2020: 80% dos adolescentes são insuficientemente ativos).', ['Quais são os determinantes da saúde em sua comunidade? Quais existem e quais faltam?', 'Por que o sedentarismo é um problema de saúde pública? Quais fatores contribuem para isso entre jovens?']),
  createLesson('g1-ef-b1-l3', 'L3: Aptidão Física — Componentes e Avaliação', 'educacao_fisica', 'Aptidão física: capacidade de realizar atividades físicas de forma eficiente. Componentes relacionados à saúde: resistência cardiorrespiratória (VO2 máx), força/resistência muscular, flexibilidade, composição corporal (IMC, percentual de gordura). Componentes relacionados à performance: velocidade, agilidade, equilíbrio, coordenação, potência, tempo de reação. Avaliação funcional: testes práticos (flexão de braço, abdominal, sentar e alcançar, shuttle run). IMC: cálculo e limitações (não diferencia músculo de gordura).', ['Realize e registre os testes de aptidão física: anote seus resultados e interprete.', 'O IMC é suficiente para avaliar a saúde de alguém? Quais outros indicadores são importantes?']),
  createLesson('g1-ef-b1-l4', 'L4: Atletismo — Fundamentos e História', 'educacao_fisica', 'Atletismo: a "mãe dos esportes". Origem nas Olimpíadas antigas (Grécia, 776 a.C.) e nas Olimpíadas modernas (Atenas, 1896). Modalidades: corridas (rasos, meio-fundo, fundo, revezamento, obstáculos), saltos (altura, distância, triplo, vara), arremessos e lançamentos (disco, dardo, martelo, peso), provas combinadas (heptatlo, decatlo). Técnica básica de corrida: postura, passada, respiração. Atletismo no Brasil: competições e atletas de destaque. Atletismo como exercício cotidiano.', ['Pratique a técnica básica de corrida e registre suas sensações.', 'Pesquise um atleta brasileiro de atletismo e apresente sua trajetória para a turma.']),
  createLesson('g1-ef-b1-l5', 'L5: Futebol e Futsal — Técnica, Tática e Cultura', 'educacao_fisica', 'Futebol: o esporte mais popular do Brasil e do mundo. História: origem na Inglaterra (séc. XIX), chegada ao Brasil (Charles Miller, 1894), democratização e identidade nacional. Técnica individual: condução, passe, chute, cabeçada, drible. Tática coletiva: sistemas de jogo (4-3-3, 4-4-2), posições, movimentação. Futsal: variante adaptada, mais técnica e rápida. Futebol feminino: trajetória de lutas e conquistas. Futebol e cultura: o que o futebol revela sobre a sociedade brasileira?', ['Pratique os fundamentos técnicos do futebol/futsal em situação de jogo.', 'O futebol é "o esporte do povo"? Que relação o futebol tem com a identidade brasileira?']),
  createLesson('g1-ef-b1-l6', 'L6: Voleibol — Fundamentos e Variações', 'educacao_fisica', 'Voleibol: criado por William Morgan (1895, EUA). Chegou ao Brasil em 1915. Regras básicas: 6 jogadores por time, 3 toques máximos, rodízio, sets de 25 pontos (5º set até 15). Fundamentos: saque (por baixo, tênis, viagem, jump), recepção (manchete, toque), levantamento, ataque (cortada), bloqueio, defesa. Beach Volley: variação olímpica em duplas. Voleibol brasileiro: potência mundial (homens e mulheres). Prática: exercícios de manchete, levantamento e ataque progressivos.', ['Pratique os fundamentos do voleibol em situação de jogo adaptado.', 'Por que o Brasil é uma das maiores potências mundiais no voleibol? Quais fatores contribuem?']),
  createLesson('g1-ef-b1-l7', 'L7: Basquetebol — Fundamentos e Cultura', 'educacao_fisica', 'Basquetebol: criado por James Naismith (1891, EUA). Regras: 5 jogadores, cestas valem 1, 2 ou 3 pontos, tempo regulamentar (4 quartos de 10 min), faltas. Fundamentos: drible (proteção, controle, velocidade), passe (peito, picado, longo, acima da cabeça), arremesso (bandeja, jump, lance livre), marcação. NBA e basquete mundial. Streetball e basquete de rua. 3x3 basquete (olímpico desde Tóquio 2020). Basquete no Brasil: histórico e situação atual. Conexão cultura: hip-hop e basquete nos EUA.', ['Pratique os fundamentos do basquete em situação de jogo.', 'Como o basquete e a cultura do hip-hop estão relacionados nos Estados Unidos e no Brasil?']),
  createLesson('g1-ef-b1-l8', 'L8: Handebol — Fundamentos e Táticas', 'educacao_fisica', 'Handebol: criado na Europa (séc. XIX/XX). Regras: 7 jogadores (incluindo goleiro), área de gol (6 metros — exclusiva do goleiro), gol após 3 passos sem driblar, tempo 2 × 30 minutos. Fundamentos: passe (lateral, por cima), recepção, drible, arremesso (em apoio, em suspensão, mergulho), bloqueio, goleiro. Táticas: defesa (5:1, 6:0, 3:2:1), ataque em movimentação. Handebol de areia (beach handball). Handebol no Brasil: Liga Nacional, seleção masculina e feminina.', ['Pratique os fundamentos do handebol em situação de jogo.', 'O handebol é um esporte pouco praticado fora da escola no Brasil. Por que isso acontece?']),
  createLesson('g1-ef-b1-l9', 'L9: Jogos e Brincadeiras Populares', 'educacao_fisica', 'Jogos e brincadeiras como patrimônio cultural. Jogos tradicionais brasileiros: pipa/pandorga, amarelinha, pião, bolinha de gude, queimada, cabo de guerra, esconde-esconde, pular corda. Jogos indígenas: arco e flecha, corrida de tora (Krahô — povo do Tocantins!), natação, wrestling. Jogos afro-brasileiros: capoeira (luta/dança/jogo). Jogo como direito da criança (ECA). Jogos eletrônicos vs. jogos físicos: impacto na saúde. Resgatando brincadeiras populares com jovens do Ensino Médio.', ['Pesquise jogos e brincadeiras tradicionais do Tocantins/região de Palmas. Apresente para a turma.', 'Organize um momento de brincadeiras tradicionais: que valor isso tem para você e para a turma?']),
  createLesson('g1-ef-b1-l10', 'L10: Dança — Linguagem Corporal e Cultura', 'educacao_fisica', 'Dança como linguagem do corpo: expressão de emoções, culturas e identidades. Tipos de dança: populares (forró, baião, sertanejo, funk, samba), clássicas (ballet, valsa, tango), étnicas (danças indígenas, africanas), contemporâneas (street dance, hip-hop). Danças do Tocantins: o Carnaval de Palmas, a Caprichosa, danças dos povos Karajá e Krahô. Dança e saúde: benefícios físicos (coordenação, equilíbrio, cardiorrespiratório) e mentais (expressão, bem-estar). Preconceito em relação à dança: discussão crítica.', ['Pesquise uma dança típica do Tocantins ou da região: sua história, características e função social.', 'Participe de uma atividade de dança: qual emoção a dança te permitiu expressar?']),
  createLesson('g1-ef-b1-l11', 'L11: Lutas — Fundamentos e Diversidade', 'educacao_fisica', 'Lutas como manifestação da cultura corporal. Origem: necessidade de sobrevivência, ritualismo, defesa. Lutas e artes marciais no mundo: Judô (Japão), Karatê (Japão/Okinawa), Taekwondo (Coreia), Wrestling (universal), Boxe (universal), Kung Fu (China). Lutas brasileiras: Capoeira (Brasil, UNESCO — patrimônio imaterial da humanidade 2014), Luta Olímpica Brasileira. Lutas nas Olimpíadas. Filosofia das lutas: disciplina, respeito, autocontrole, ética. EF na escola: lutas como ferramenta pedagógica (não violência).', ['O que diferencia "luta" de "violência"? Como as lutas ensinam valores?', 'Pesquise a Capoeira: qual sua origem histórica? O que ela representa para a cultura afro-brasileira?']),
  createLesson('g1-ef-b1-l12', 'L12: Ginástica — Fundamentos e Variedades', 'educacao_fisica', 'Ginástica: base de todos os esportes. Variedades: Ginástica Artística (aparelhos — solo, barras, argolas, trave, salto), Ginástica Rítmica (fitas, arcos, maças, bolas, cordas), Ginástica Aeróbica, Ginástica para Todos (GpT — inclusiva, não competitiva), Ginástica Acrobática. Ginástica na escola: capacidades físicas, postura, coordenação. História: dos antigos gregos ao Cirque du Soleil. Ginástica brasileira: Rebeca Andrade — maior conquista histórica (Tóquio 2020 e Paris 2024). Ginástica e inclusão: adaptações para diferentes corpos.', ['Que habilidades da ginástica você já possui? Quais quer desenvolver?', 'Como Rebeca Andrade representa não apenas o esporte, mas a luta e a representatividade?']),
  createLesson('g1-ef-b1-l13', 'L13: Atividade Física e Saúde Mental', 'educacao_fisica', 'A relação entre exercício físico e saúde mental é comprovada cientificamente. Mecanismos: liberação de endorfinas, serotonina, dopamina; redução do cortisol (hormônio do estresse). Benefícios para saúde mental: reduz ansiedade e depressão, melhora o sono, aumenta a autoestima, fortalece a resiliência. Adolescência: período de maior vulnerabilidade emocional. O exercício como parte do cuidado integral com a saúde. Acesso à atividade física: disparidades sociais (quem pode praticar o quê?). EF na escola: garantia de acesso.', ['Você já percebeu mudança no seu humor após praticar atividade física? Como foi?', 'Quais barreiras os jovens do Tocantins enfrentam para praticar atividade física regularmente?']),
  createLesson('g1-ef-b1-l14', 'L14: Esportes Alternativos e Radicais', 'educacao_fisica', 'Esportes alternativos: fora do calendário olímpico tradicional, mas muito populares entre jovens. Skate (olímpico desde Tóquio 2020), Surfe (olímpico desde Tóquio), Escalada, Bicicleta BMX. Street sports: skateboarding, parkour, breaking (break dance — olímpico em Paris 2024). Esportes radicais: rapel, kitesurf, rafting, asa-delta. Esportes aquáticos no Tocantins: o Rio Araguaia e o Rio Tocantins como palco para esportes radicais (rafting, canoagem, stand-up paddle). Risco, adrenalina e responsabilidade.', ['Que esportes alternativos são praticados em Palmas ou no Tocantins? Pesquise e compartilhe.', 'O que atrai os jovens aos esportes radicais? Quais valores eles expressam?']),
  createLesson('g1-ef-b1-l15', 'L15: Corpo e Sociedade — Padrões de Beleza', 'educacao_fisica', 'A mídia e os padrões corporais: a construção social do "corpo ideal". Impacto na saúde mental dos jovens: transtornos alimentares (anorexia, bulimia, ortorexia, vigorexia), dismorfofobia, pressão por magreza ou por muscular. Corpo e raça: padrão eurocentrado de beleza. Corpo e gênero: expectativas diferentes para homens e mulheres. Movimento body positive: aceitação da diversidade corporal. A EF como espaço de valorização de TODOS os corpos. Reflexão: o esporte deve incluir, não excluir.', ['Como a mídia influencia a percepção que você tem do seu próprio corpo?', 'O que é "gordofobia" e como ela se manifesta no esporte e na EF escolar?']),
  createLesson('g1-ef-b1-l16', 'L16: Esporte e Ética', 'educacao_fisica', 'Fair play (jogo limpo): respeitar as regras, o adversário e o árbitro. Ética esportiva: o esporte como escola de valores. Doping: uso de substâncias proibidas — casos famosos (Ben Johnson, Lance Armstrong, Maradona). Agência Mundial Antidoping (WADA). Violência no esporte: hooliganism, racismo, homofobia, violência física. Corrupção esportiva: manipulação de resultados, FIFA-gate. O esporte como reflexo da sociedade: os valores da sociedade aparecem no esporte. Esporte como ferramenta de paz e coesão social.', ['O que é fair play? Como ele se aplica além do esporte (na vida cotidiana)?', 'Pesquise um caso de doping famoso: quais foram as consequências para o atleta e para o esporte?']),
  createLesson('g1-ef-b1-l17', 'L17: Esportes Coletivos — Prática Integrada', 'educacao_fisica', 'Prática integrada dos esportes coletivos estudados no bimestre: futebol, futsal, voleibol, basquete, handebol. Festival esportivo: mini-torneio entre equipes mistas. Foco: participação, fair play, trabalho em equipe, não apenas a vitória. Postos de jogo: rotação para que todos experimentem diferentes posições. Reflexão: o que um esporte coletivo exige de cada participante além da habilidade técnica? Avaliação participativa: o professor observa engajamento, respeito e cooperação.', ['Participe do festival esportivo: qual foi o momento mais marcante para você?', 'O que você aprendeu sobre trabalho em equipe nesta prática?']),
  createLesson('g1-ef-b1-l18', 'L18: Revisão do Bimestre 1', 'educacao_fisica', 'Revisão do 1º Bimestre de Educação Física: conceitos de EF no EM, saúde (conceito amplo, determinantes), aptidão física (componentes, avaliação), atletismo, futebol/futsal, voleibol, basquete, handebol, jogos populares, dança, lutas, ginástica, atividade física e saúde mental, esportes alternativos/radicais, corpo e sociedade, ética esportiva. Avaliação: parte prática (participação, habilidades) + parte teórica (conceitos básicos). Reflexão: o que a EF acrescentou à sua vida neste bimestre?', ['Resolva este questionário de revisão dos conteúdos teóricos do 1º Bimestre.', 'Qual foi a prática corporal mais significativa para você neste bimestre? Por quê?']),
];

export const efLessonsB2: Lesson[] = [
  createLesson('g1-ef-b2-l1', 'L1: Jogos Olímpicos — História e Valores', 'educacao_fisica', 'As Olimpíadas na Antiguidade: Grécia antiga, 776 a.C., em Olímpia. Dedicadas a Zeus. Modalidades: corrida, pentatlo, luta, pugilismo, carro com cavalos. Apenas homens livres gregos participavam. A trégua olímpica: suspensão das guerras. Olimpíadas Modernas: Pierre de Coubertin, Atenas 1896. Carta Olímpica: valores — excelência, respeito, amizade. Brasil nas Olimpíadas: primeira participação (1920), Rebeca Andrade, João Gomes Junior, Isaquias Queiroz. Paris 2024: resultados brasileiros. Paralimpíadas: atletas com deficiência.', ['Pesquise a trajetória de um atleta olímpico brasileiro. O que ele/ela representa além do esporte?', 'Os valores olímpicos (excelência, respeito, amizade) ainda fazem sentido no esporte atual? Argumente.']),
  createLesson('g1-ef-b2-l2', 'L2: Natação — Fundamentos e Saúde', 'educacao_fisica', 'Natação: um dos esportes mais completos para a saúde. Benefícios: cardiovascular, fortalecimento muscular, sem impacto nas articulações, reabilitação. Os 4 nados olímpicos: crawl (livre — mais rápido), costas, peito (mais lento), borboleta (mais exigente). Técnica básica: posição horizontal, respiração, braçada, pernada, saída, virada. Natação no Brasil: competições, clubes, acesso desigual (a maioria dos brasileiros não sabe nadar). Afogamento: terceira causa de morte por acidente no Brasil. Rios do Tocantins: espaços de lazer e perigo.', ['Você sabe nadar? Qual é sua relação com o ambiente aquático?', 'Por que tantos brasileiros não sabem nadar? Quais são as barreiras de acesso?']),
  createLesson('g1-ef-b2-l3', 'L3: Esportes de Raquete — Tênis, Tênis de Mesa e Badminton', 'educacao_fisica', 'Esportes de raquete: precisão, velocidade e coordenação. Tênis: campo de saibro/grama/duro, sets, jogos, pontos. Grand Slams: Roland Garros, Wimbledon, US Open, Australian Open. Tênis no Brasil: João Fonseca, Gustavo Kuerten. Tênis de Mesa (Ping-Pong): velocidade impressionante, popular na Ásia, mesa padrão, borrachas. Brasil no tênis de mesa. Badminton: mais rápido dos esportes de raquete, peteca, quadra fechada. Esportes de raquete e inclusão: adaptações para cadeirantes. Prática: fundamentos de badminton ou tênis de mesa.', ['Pratique os fundamentos do tênis de mesa ou badminton em situação de jogo.', 'Que habilidades físicas e cognitivas os esportes de raquete desenvolvem?']),
  createLesson('g1-ef-b2-l4', 'L4: Esportes de Combate — Judô e Capoeira', 'educacao_fisica', 'Judô: criado por Jigoro Kano (Japão, 1882). "Judô" = "caminho suave." Princípios: máxima eficiência com mínimo esforço, bem-estar mútuo. Técnicas: quedas (ippon-seoi-nage, osoto-gari), imobilizações, estrangulamentos. Graduação por faixas. Judô como filosofia de vida: respeito, disciplina, perseverança. Brasil no judô olímpico: medalhistas históricos. Capoeira (revisão aprofundada): roda, jogo, música (berimbau, pandeiro, atabaque), angola vs. regional, ginga. Capoeira no Tocantins: grupos locais.', ['O que diferencia o judô de outras lutas? Quais valores ele transmite?', 'Como a Capoeira funciona como resistência cultural dos povos afro-brasileiros?']),
  createLesson('g1-ef-b2-l5', 'L5: Esportes de Aventura na Natureza', 'educacao_fisica', 'Esportes de aventura na natureza (EAN): integração entre atividade física e ambiente natural. Categorias: terrestres (trilha, mountain bike, escalada, corrida de aventura), aquáticos (canoagem, rafting, stand-up paddle, mergulho), aéreos (parapente, asa-delta, bungee jumping). O Tocantins como destino de esportes de aventura: o Parque Estadual do Jalapão, Ilha do Bananal, Serras Gerais do Tocantins. Sustentabilidade: praticando na natureza com responsabilidade. Risco calculado: segurança nos esportes de aventura.', ['Que esportes de aventura você poderia praticar no Tocantins? Pesquise locais e condições.', 'Como os esportes de aventura nos ensinam a respeitar a natureza?']),
  createLesson('g1-ef-b2-l6', 'L6: Nutrição e Desempenho Esportivo', 'educacao_fisica', 'Alimentação como combustível do corpo. Macronutrientes: carboidratos (energia imediata — grãos, frutas, legumes), proteínas (construção muscular — carnes, ovos, leguminosas), lipídios (energia reserva e hormônios — azeite, abacate, castanhas). Micronutrientes: vitaminas e minerais essenciais. Hidratação: água e eletrólitos durante o exercício. Alimentação pré-exercício, intra e pós. Suplementação: quando é necessária e quando é desnecessária (a maioria dos adolescentes NÃO precisa de suplemento). Alimentos ultra-processados e desempenho.', ['Analise sua alimentação atual: ela suporta seu nível de atividade física?', 'Você consome suplementos? São necessários? Pesquise e argumente.']),
  createLesson('g1-ef-b2-l7', 'L7: Lesões Esportivas e Prevenção', 'educacao_fisica', 'Lesões esportivas: mais comuns e como prevenir. Entorse (torção de ligamento): o mais comum em futebol, basquete. Distensão muscular (estiramento). Tendinite: inflamação do tendão por sobrecarga. Fratura por estresse. Contusão (pancada). Prevenção: aquecimento adequado (10-15 min de atividade aeróbica leve + mobilidade dinâmica), técnica correta, equipamento adequado, descanso suficiente, hidratação. Primeiros socorros: PRICE (Protection, Rest, Ice, Compression, Elevation). Quando procurar médico. Volta ao esporte após lesão.', ['Por que o aquecimento é importante? O que acontece se você não aquece?', 'Como você aplicaria os primeiros socorros (PRICE) em uma entorse de tornozelo?']),
  createLesson('g1-ef-b2-l8', 'L8: Esporte e Inclusão Social', 'educacao_fisica', 'O esporte como ferramenta de inclusão social. Projetos sociais esportivos: como o esporte pode transformar vidas em comunidades vulneráveis. Exemplos brasileiros: Instituto Ayrton Senna, IEFES (esporte na periferia), projetos de favela. Esporte e redução da violência: evidências e limites (o esporte não resolve sozinho problemas estruturais). Esporte Paralímpico: atletas com deficiência quebrando barreiras. Esporte e igualdade de gênero: lutas históricas das mulheres para participar do esporte. Esporte e raça: o racismo no esporte brasileiro.', ['Pesquise um projeto social esportivo em Palmas ou no Tocantins. Como ele funciona?', 'O esporte sozinho é suficiente para combater a desigualdade social? Argumente.']),
  createLesson('g1-ef-b2-l9', 'L9: Ginástica Rítmica e Artística — Aprofundamento', 'educacao_fisica', 'Ginástica Rítmica: mulheres (e homens no Brasil a partir de 2021). Aparelhos: corda, arco, bola, maças, fita. Elementos: corpo (onda, equilíbrio, pivô, salto, flexibilidade), técnicos (lançamentos, recuperações, rolamentos, trocas). Copa do Mundo, Olimpíadas. Ginástica Artística feminina e masculina: Rebeca Andrade como ícone. Aparelhos: solo, trave (feminino), barras assimétricas (feminino), paralelas (masculino), argolas, cavalo, salto. Ginástica para Todos (GpT): sem competição, para todos os corpos. Festival escolar de ginástica.', ['Qual a diferença entre Ginástica Rítmica e Artística? Quais habilidades cada uma exige?', 'Como Rebeca Andrade representa a luta das mulheres negras no esporte de alto rendimento?']),
  createLesson('g1-ef-b2-l10', 'L10: Yoga e Práticas Corporais Integrativas', 'educacao_fisica', 'Práticas corporais integrativas: abordagem que integra corpo, mente e espírito. Yoga: origem na Índia antiga (~5.000 anos). Tipos: Hatha yoga (posições — asanas), Vinyasa (fluxo), Kundalini (energia), Yin (passivo, longo). Benefícios: flexibilidade, força, equilíbrio, redução do estresse, melhora da atenção. Meditação: atenção plena (mindfulness). Tai chi chuan: chinês, movimento lento, meditação em movimento. Pilates: alemão (Joseph Pilates), foco no core, reabilitação. Práticas integrativas no SUS (PNPIC). Aplicação na escola: gestão do estresse.', ['Experimente uma prática de yoga ou meditação. Como você se sentiu?', 'Qual a diferença entre yoga e ginástica tradicional? O que cada uma oferece?']),
  createLesson('g1-ef-b2-l11', 'L11: Esporte e Mídia', 'educacao_fisica', 'A relação entre esporte e mídia. A mídia esportiva: transmissões ao vivo, jornalismo esportivo, redes sociais de atletas. Como a mídia molda o esporte: quais esportes ganham mais visibilidade? Futebol masculino vs. outras modalidades. Esporte feminino e cobertura midiática: disparidade histórica. Patrocínio e marketing esportivo. Celebridades esportivas: construção de imagem pública. Esport (videogames competitivos): nova modalidade reconhecida como esporte. Influência da mídia no consumo de produtos esportivos. Consumo consciente vs. consumismo.', ['O esporte feminino recebe menos atenção da mídia? Pesquise dados e apresente.', 'Os esports devem ser reconhecidos como esporte olímpico? Argumente.']),
  createLesson('g1-ef-b2-l12', 'L12: Planejamento da Atividade Física Pessoal', 'educacao_fisica', 'Autonomia na atividade física: saber planejar sua própria rotina. Princípios do treinamento: sobrecarga progressiva, especificidade, reversibilidade (use it or lose it), variação. Frequência, intensidade, tempo, tipo (FITT). Exemplos de programas para jovens sedentários: começando com 20 min de caminhada 3x/semana. OMS recomenda: 150-300 min/semana de atividade aeróbica moderada para adolescentes. Monitoramento: frequência cardíaca, percepção de esforço (Escala de Borg). Apps de atividade física: ferramenta útil. Criando um plano pessoal de AF.', ['Crie um plano pessoal de atividade física para 4 semanas, baseado nos princípios aprendidos.', 'Quais barreiras você encontra para se exercitar regularmente? Como superar cada uma?']),
  createLesson('g1-ef-b2-l13', 'L13: Esportes Coletivos — Aprofundamento Tático', 'educacao_fisica', 'Aprofundando a tática nos esportes coletivos. Futebol: conceitos táticos — triangulação, pressing alto, posse de bola. Voleibol: sistemas de defesa (6 ou 5-1), distribuição de levantamento. Basquete: pick-and-roll, zone defense, fast break. Handebol: contra-ataque, pivô, arremesso em suspensão. Vídeo-análise: assistir e analisar jogadas táticas profissionais. Desenvolver visão de jogo: perceber o espaço, antecipar jogadas. O pensamento tático como habilidade cognitiva — transferível para a vida.', ['Assista um vídeo de tática esportiva e explique a jogada para a turma.', 'Como o pensamento tático no esporte se transfere para outras áreas da vida?']),
  createLesson('g1-ef-b2-l14', 'L14: Dança Contemporânea e Street Dance', 'educacao_fisica', 'Dança contemporânea: sem forma fixa, expressa o corpo e as ideias do artista. Breaking (break dance): surgiu no Bronx, Nova York, anos 1970, ligado ao hip-hop. Movimentos: toprock, downrock (footwork), freezes, power moves (windmill, headspin). Breaking nas Olimpíadas (Paris 2024). Street dance no Brasil: muito popular, competições (campeonatos de breaking). Hip-hop como cultura: rap, DJing, grafite, dança — os 4 elementos. Dança como resistência: as culturas periféricas expressas pelo corpo. Prática: introdução ao breaking.', ['O que é o hip-hop como cultura? Como a dança (breaking) faz parte disso?', 'Pratique movimentos básicos de breaking: o que você descobriu sobre seu próprio corpo?']),
  createLesson('g1-ef-b2-l15', 'L15: Esportes Paralímpicos e Acessibilidade', 'educacao_fisica', 'Jogos Paralímpicos: criados por Ludwig Guttmann (1948, Londres — pacientes de Stoke Mandeville). Primeiro Paralímpico moderno (Roma, 1960). Modalidades: atletismo adaptado, natação, basquete em cadeira de rodas, goalball, bocce, halterofilismo paralímpico, natação, tênis de mesa. Classificação funcional: avalia o impacto da deficiência no desempenho. Brasil Paralímpico: potência mundial — Daniel Dias, Terezinha Guilhermina, Fernando Fernandes. Acessibilidade nas quadras escolares: barreiras e soluções. Esporte como direito de todos.', ['Experimente uma modalidade adaptada (ex: basquete em cadeira de rodas). Como foi?', 'Quais barreiras de acessibilidade você identifica na sua escola para a prática esportiva?']),
  createLesson('g1-ef-b2-l16', 'L16: Saúde e Prevenção de Doenças Crônicas', 'educacao_fisica', 'Doenças Crônicas Não Transmissíveis (DCNT): hipertensão, diabetes tipo 2, obesidade, doenças cardiovasculares, câncer. Representam 70% das mortes no Brasil (IBGE). Fatores de risco modificáveis: sedentarismo, alimentação inadequada, tabagismo, álcool, estresse. Atividade física na prevenção e no tratamento de DCNTs: evidências científicas. Adolescência como janela de oportunidade: hábitos estabelecidos agora persistem por décadas. A EF na escola como política pública de saúde. DCNT e desigualdade: populações mais pobres são mais afetadas.', ['Como a atividade física previne doenças crônicas? Explique o mecanismo para pelo menos 2 doenças.', 'Você tem familiares com DCNT? Como a EF poderia ter feito diferença?']),
  createLesson('g1-ef-b2-l17', 'L17: Festival de Práticas Corporais', 'educacao_fisica', 'Festival integrado: apresentação e prática de diferentes manifestações da cultura corporal. Estações: esportes coletivos (futebol, vôlei, basquete), dança (forró, breaking, dança folclórica), lutas (capoeira, judô adaptado), ginástica (GpT), esportes alternativos (slackline, xadrez esportivo). Participação de todos: o festival celebra a diversidade de corpos e habilidades. Foco: explorar, experimentar, celebrar — não competir. Registro: fotos/vídeos para portfólio da turma. Reflexão coletiva após o festival.', ['Participe do festival: experimente pelo menos 3 práticas corporais diferentes.', 'Qual prática corporal foi mais surpreendente para você? Por quê?']),
  createLesson('g1-ef-b2-l18', 'L18: Revisão do Bimestre 2', 'educacao_fisica', 'Revisão do 2º Bimestre: Olimpíadas, natação, esportes de raquete, lutas (judô/capoeira), esportes de aventura, nutrição esportiva, lesões e prevenção, inclusão social pelo esporte, ginástica rítmica/artística, yoga/práticas integrativas, esporte e mídia, planejamento de AF, tática esportiva, dança contemporânea/breaking, esportes paralímpicos, prevenção de DCNTs. Avaliação: parte prática + reflexão sobre valores. Qual prática corporal você quer continuar fazendo fora da escola?', ['Resolva o questionário de revisão dos conteúdos teóricos do 2º Bimestre.', 'Qual foi a prática corporal mais significativa do 2º Bimestre? Como ela impactou sua saúde ou bem-estar?']),
];

export const efLessonsB3: Lesson[] = [
  createLesson('g1-ef-b3-l1', 'L1: Esporte e Política', 'educacao_fisica', 'A relação inseparável entre esporte e política. Histórico: Olimpíadas de Berlim 1936 (nazismo e Jesse Owens), boicotes olímpicos (1980/1984 — Guerra Fria), Black Power nas Olimpíadas de 1968 (Tommie Smith e John Carlos). Nelson Mandela e o Rugby na África do Sul ("Invictus"). Esporte e ditadura militar no Brasil: a seleção de 1970 e o regime militar. Futebol e diplomacia: "a bola rola além das fronteiras." A política do COI (Comitê Olímpico Internacional): neutralidade? Esporte como arena de disputas simbólicas.', ['Como o esporte pode ser usado como instrumento político? Dê exemplos históricos.', 'O esporte deveria ser politicamente neutro? Ou os atletas têm responsabilidade de se posicionar?']),
  createLesson('g1-ef-b3-l2', 'L2: Handebol e Vôlei de Praia — Aprofundamento', 'educacao_fisica', 'Handebol: aprofundamento das táticas defensivas e ofensivas. Sistemas defensivos: 6:0 (fechado), 5:1 (misto), 3:2:1 (aberto). Sistemas ofensivos: circulação, cruzamento, pivô, contra-ataque. Regras menos conhecidas: penalidade progressiva, cartão vermelho e azul. Vôlei de praia: diferenças do indoor (duplas, sem rodízio, máximo 3 saques errados, 21 pontos). Habilidades específicas: saque de "viagem", manchete de costas, cortada na areia. Prática: jogo de vôlei de praia adaptado. Copa do Mundo de Handebol e Liga de Vôlei de Praia.', ['Pratique um jogo de handebol e/ou vôlei de praia adaptado.', 'Qual é a diferença mais importante entre o vôlei indoor e o vôlei de praia?']),
  createLesson('g1-ef-b3-l3', 'L3: Xadrez e Esportes de Mesa', 'educacao_fisica', 'Xadrez: jogo de estratégia com 3.000 anos de história. Origem: Índia (Chaturanga). Regras básicas: peças, movimentos, xeque, xeque-mate, empate. Notação algébrica. Abertura, meio-jogo, final. Benefícios cognitivos: raciocínio lógico, planejamento, tomada de decisão, memória, concentração. Xadrez nas escolas: programas internacionais e brasileiros. Magnus Carlsen, Garry Kasparov, Fischer. Damas: versão simplificada. Esportes de mente: xadrez, damas, go, bridge. Esportes e cognição: como jogar fortalece o cérebro.', ['Aprenda os movimentos básicos das peças do xadrez e jogue uma partida.', 'Quais habilidades cognitivas o xadrez desenvolve? Como elas se transferem para a escola?']),
  createLesson('g1-ef-b3-l4', 'L4: Treinamento Físico Funcional', 'educacao_fisica', 'Treinamento funcional: exercícios que imitam movimentos do cotidiano, trabalhando múltiplos grupos musculares e planos de movimento. Princípio: treinar o MOVIMENTO, não o músculo isolado. Exercícios funcionais: agachamento (mimetiza sentar/levantar), levantamento terra (pegar objetos do chão), prancha (estabilidade), burpee (explosão total). Comparação com musculação tradicional (isolamento). Treinamento funcional para jovens: desenvolvimento de coordenação, equilíbrio e força de forma global. Circuito funcional: estações com exercícios variados.', ['Execute o circuito funcional: registre como cada exercício usa o corpo como unidade.', 'Por que o treinamento funcional é considerado mais "real" do que a musculação tradicional?']),
  createLesson('g1-ef-b3-l5', 'L5: Esporte Feminino — História e Conquistas', 'educacao_fisica', 'A trajetória histórica das mulheres no esporte. Exclusão inicial: mulheres não participavam das Olimpíadas antigas. Luta pela inclusão: primeiros esportes olímpicos femininos (atletismo e ginástica em 1928). Decreto de 1941 no Brasil: proibia mulheres de praticar esportes violentos (só revogado em 1979). Futebol feminino: proibição no Brasil (1941-1979), reconstrução, conquistas. Marta: maior artilheira da história da Copa do Mundo (homens e mulheres). Tifanny Abreu no vôlei: transexualidade e inclusão. Disparidade salarial e de investimento.', ['Quais barreiras históricas as mulheres enfrentaram para praticar esportes?', 'A disparidade salarial entre atletas homens e mulheres é justa? Argumente.']),
  createLesson('g1-ef-b3-l6', 'L6: Cuidados com o Corpo — Ergonomia e Postura', 'educacao_fisica', 'Ergonomia: ciência que adapta o ambiente ao ser humano. Postura correta: coluna vertebral neutra, ombros alinhados, pés apoiados. Problemas posturais comuns em adolescentes: escoliose (curvatura lateral), hiperlordose (exagero da curva lombar), cifose (corcunda). Causas: sedentarismo, mochila pesada, postura incorreta ao usar celular (text neck), posição incorreta ao estudar. Exercícios corretivos: fortalecimento do core, alongamento de flexores do quadril, exercícios para escápulas. Ergonomia digital: como usar celular e computador sem prejudicar a postura.', ['Verifique sua postura agora: você está com alguma curvatura incorreta?', 'Quais mudanças de hábito você pode fazer hoje para melhorar sua postura?']),
  createLesson('g1-ef-b3-l7', 'L7: Natação e Esportes Aquáticos no Tocantins', 'educacao_fisica', 'Água como elemento da cultura tocantinense. O Rio Araguaia: o mais belo rio de planície do Brasil, palco de lazer e esportes. Porto Nacional: pesca esportiva. Balneários e praias fluviais do Tocantins. Esportes aquáticos: canoagem (slalom e velocidade), stand-up paddle (SUP), kayak, remo, polo aquático. Natação adaptada: para pessoas com deficiência. Segurança na água: afogamento — como prevenir. Natação como habilidade de sobrevivência. A praia do Prata em Palmas como espaço de lazer e esporte.', ['Que esportes aquáticos você já praticou nos rios ou lagos do Tocantins?', 'Por que a natação é considerada uma habilidade de sobrevivência? Como democratizá-la?']),
  createLesson('g1-ef-b3-l8', 'L8: Dança Folclórica e Identidade Regional', 'educacao_fisica', 'Dança folclórica brasileira como patrimônio cultural. Danças por região: Nordeste (forró, coco, frevo, maracatu, xaxado), Sul (gaúcho, vanerão), Sudeste (samba, congada), Norte (carimbó, lambada, brega). Danças do Tocantins: catira/cateretê (caipira do cerrado), forrózinho, quadrilha (especialmente nas festas juninas), danças indígenas dos povos Xerente, Karajá e Krahô. Folclore tocantinense: Caprichosa, Boi Roubado. Dança folclórica e identidade: o que dançamos revela quem somos. Prática: aprender um passo de dança regional.', ['Pesquise uma dança folclórica específica do Tocantins: sua origem, características e contexto.', 'Aprenda um passo básico de uma dança regional: como você se sentiu dançando?']),
  createLesson('g1-ef-b3-l9', 'L9: Atividade Física ao Longo da Vida', 'educacao_fisica', 'Atividade física em diferentes fases da vida. Infância: desenvolvimento motor fundamental (correr, saltar, arremessar, receber). Adolescência (agora): formação óssea e muscular, hábitos que duram. Adulto jovem: manutenção, alto desempenho. Meia-idade: prevenção de DCNTs, força e flexibilidade. Idoso: equilíbrio, prevenção de quedas, manutenção cognitiva. A atividade física como investimento no futuro. Por que começar agora? Janela de oportunidade: o período entre 15-25 anos é crítico para construir base óssea e muscular.', ['Entreviste um familiar idoso sobre como a atividade física mudou em sua vida. Apresente para a turma.', 'Por que hábitos de atividade física estabelecidos na adolescência tendem a persistir na vida adulta?']),
  createLesson('g1-ef-b3-l10', 'L10: Esporte e Sustentabilidade', 'educacao_fisica', 'Esporte e meio ambiente: uma relação de dependência. Esportes que dependem da natureza: surf, ski, escalada, rapel, ecoturismo. Impacto ambiental dos eventos esportivos: Copa do Mundo, Olimpíadas — consumo de água, energia, construção de estádios. Olimpíadas verdes: esforços de sustentabilidade (Paris 2024 como referência). Esportes e mudanças climáticas: neve derretendo → menos ski; recife danificado → menos surf. Esportes de aventura como ferramenta de conscientização ambiental. Leave No Trace: princípios de conduta na natureza.', ['Como as mudanças climáticas afetam a prática de esportes ao ar livre no Brasil?', 'Que medidas sustentáveis a sua escola poderia adotar nas aulas de EF e eventos esportivos?']),
  createLesson('g1-ef-b3-l11', 'L11: Projeto de Atividade Física Comunitária', 'educacao_fisica', 'EF como agente de transformação social. Projeto: planejar uma atividade física para a comunidade escolar. Etapas: identificar o público (idosos, crianças, adolescentes), escolher a atividade (caminhada, dança, esporte), definir local e horário, divulgar, executar, avaliar. Exemplos: mutirão esportivo no bairro, aula de dança para pais e filhos, caminhada da saúde. O estudante como agente de saúde: usar o que aprendeu em EF para beneficiar outros. Autonomia: a EF não termina na escola.', ['Em grupos: planejem um evento de atividade física comunitária na escola ou no bairro.', 'Como a prática de atividade física pode transformar a sua comunidade?']),
  createLesson('g1-ef-b3-l12', 'L12: Avaliação da Aptidão Física — Revisão', 'educacao_fisica', 'Reavaliação da aptidão física: comparar os resultados do início do ano com os atuais. Testes: resistência cardiorrespiratória (Cooper ou Beep test), força/resistência muscular (flexão de braço, abdominal), flexibilidade (sentar e alcançar), composição corporal (IMC). O que mudou? Por quê? Análise crítica dos testes: o que eles medem e o que não medem. Metas: definir objetivos para o próximo semestre. Auto-eficácia: acreditar na própria capacidade de melhorar. O corpo é adaptável — o esforço traz resultado.', ['Compare seus resultados da avaliação atual com os do início do ano. O que mudou?', 'Quais hábitos de atividade física você vai manter após o fim das aulas de EF?']),
  createLesson('g1-ef-b3-l13', 'L13: Esportes de Inverno e Modalidades Exóticas', 'educacao_fisica', 'Esportes de inverno: ski alpino e cross-country, snowboard, patinação no gelo (artística e velocidade), curling, biathlon, biatlo. Por que importa para um brasileiro? Cultura esportiva global, Olimpíadas de Inverno, atletas brasileiros de ski (Jaqueline Mourão). Modalidades exóticas olímpicas: caiaque slalom, BMX, triatlo, pentatlo moderno, canoagem, hipismo. Modalidades em discussão para Paris 2028: squash, críquete, flags football. Diversidade esportiva: o mundo tem mais de 200 esportes reconhecidos. Qual esporte você inventaria?', ['Pesquise um esporte olímpico que você não conhecia. Apresente suas regras e origem.', 'Crie as regras de um esporte novo que combina elementos de dois esportes que você conhece.']),
  createLesson('g1-ef-b3-l14', 'L14: Futebol de Rua e Esportes Populares', 'educacao_fisica', 'O futebol de rua como escola do esporte. No Brasil, historicamente, os grandes craques aprenderam nas ruas e peladas — Pelé, Zico, Romário, Ronaldinho. O que a rua ensina que a academia não ensina: criatividade, improviso, resiliência, autodidatismo. Esportes populares não tradicionais: "Pelada" (futebol informal), "queimada" (brincadeira), "bete ombro" (tipo de baseball improvisado), "mata-mata". Esporte e democratização: quem tem acesso a esportes formais? Infraestrutura esportiva no Tocantins: o que existe e o que falta.', ['O futebol de rua está desaparecendo? O que estamos perdendo com isso?', 'Que esportes populares informais você conhece da sua cidade ou bairro?']),
  createLesson('g1-ef-b3-l15', 'L15: Saúde do Adolescente — Temas Atuais', 'educacao_fisica', 'Temas de saúde específicos para adolescentes. Desenvolvimento puberal: mudanças hormonais, corporais, emocionais — normalidade e variações. Saúde sexual: prevenção de DSTs, gravidez na adolescência, consentimento. Uso de álcool e outras drogas: impacto no cérebro adolescente (mais vulnerável), performance esportiva e cognitiva. Vício em telas e sedentarismo. Sono e desempenho: adolescentes precisam de 8-10h de sono — a maioria dorme menos. Pressão por resultados: equilíbrio entre competição e bem-estar.', ['Quais são os maiores riscos à saúde dos adolescentes na sua comunidade?', 'Como a falta de sono prejudica sua performance escolar e esportiva?']),
  createLesson('g1-ef-b3-l16', 'L16: Prática Integrada e Avaliação', 'educacao_fisica', 'Aula prática integrada: festival de práticas corporais diversificadas. Estações: esporte coletivo (à escolha da turma), dança (regional ou contemporânea), luta (capoeira ou elemento de judô), prática integrativa (yoga ou meditação), esporte individual (atletismo ou ginástica). Avaliação participativa: o professor avalia engajamento, cooperação, respeito, esforço — não apenas habilidade técnica. Reflexão final: qual prática corporal você quer incorporar à sua vida? Por quê?', ['Participe de todas as estações da prática integrada com disposição e respeito.', 'Escreva uma reflexão: qual prática corporal do 3º Bimestre foi mais significativa para você?']),
  createLesson('g1-ef-b3-l17', 'L17: EF e ENEM — Conexões', 'educacao_fisica', 'A Educação Física no ENEM: como os temas de EF aparecem nas questões. Questões sobre: cultura corporal (história dos esportes, danças folclóricas), saúde e qualidade de vida (determinantes, atividade física e doenças), inclusão (esporte adaptado, direitos), corpo e sociedade (padrões de beleza, diversidade). Como estudar EF para o ENEM: não é sobre "nomear regras de esportes" — é sobre compreender o esporte como fenômeno cultural, social e histórico. Resolução de questões do ENEM relacionadas à EF.', ['Resolva estas 5 questões do ENEM que envolvem temas de EF.', 'Como o que você aprendeu em EF este ano pode ajudar em outras matérias do ENEM?']),
  createLesson('g1-ef-b3-l18', 'L18: Revisão do Bimestre 3', 'educacao_fisica', 'Revisão do 3º Bimestre: esporte e política, esportes de mesa, treinamento funcional, esporte feminino, ergonomia/postura, esportes aquáticos/Tocantins, dança folclórica regional, AF ao longo da vida, esporte e sustentabilidade, projeto comunitário, avaliação de aptidão, esportes exóticos, futebol de rua, saúde do adolescente, EF e ENEM. Avaliação: projeto comunitário + parte teórica. O que você vai levar de EF para sua vida?', ['Resolva o questionário de revisão dos conteúdos teóricos do 3º Bimestre.', 'Qual foi a maior aprendizagem de EF neste 3º Bimestre? Como ela impacta sua vida fora da escola?']),
];

export const efLessonsB4: Lesson[] = [
  createLesson('g1-ef-b4-l1', 'L1: Esporte de Alto Rendimento vs. Esporte Participativo', 'educacao_fisica', 'Dois modelos de esporte. Esporte de alto rendimento: foco no resultado, seleção dos melhores, treinamento intenso, profissionalização. Esporte participativo/recreativo: foco na participação, saúde, lazer, inclusão — para todos. A pirâmide do desenvolvimento esportivo: base (participação) → formação → rendimento. Crítica: o Brasil investe muito em rendimento e pouco na base. Esporte para todos como política pública. O SESI, SESC, clubes municipais. Esporte na escola: qual modelo? A EF escolar não é para formar atletas — é para formar cidadãos ativos.', ['Qual é a diferença fundamental entre esporte de rendimento e esporte participativo?', 'A escola deve priorizar esporte de rendimento (descobrir talentos) ou esporte participativo? Argumente.']),
  createLesson('g1-ef-b4-l2', 'L2: Futebol Americano e Rugby', 'educacao_fisica', 'Modalidades em crescimento no Brasil. Futebol Americano: originado do rugby inglês (séc. XIX), popularizado nos EUA. NFL: a liga mais rica do mundo. Super Bowl: maior evento esportivo americano. Regras básicas: 11 jogadores por lado, downs, touchdown, field goal. Posições: quarterback, wide receiver, lineman. Rugby: origem britânica, mais disseminado globalmente. Rugby 7s: versão olímpica. Diferenças entre rugby e futebol americano: proteções, scrums, passes. Brasil tem seleções nacionais de ambos. Flags Football: versão sem contato.', ['Quais são as 3 principais diferenças entre futebol americano e rugby?', 'Por que o futebol americano é tão popular nos EUA? Que fatores culturais explicam isso?']),
  createLesson('g1-ef-b4-l3', 'L3: Artes Marciais Mistas (MMA) e Ética Esportiva', 'educacao_fisica', 'MMA (Mixed Martial Arts): combina técnicas de várias artes marciais — boxe, luta, judô, jiujitsu, kickboxing. UFC: principal organização mundial. Atletas brasileiros: Anderson Silva, Minotauro, Cigano, Amanda Nunes. Técnicas: striking (socos, chutes), wrestling (quedas), grappling (chaves, estrangulamentos). Debate ético: o MMA é violência ou esporte? Regulamentação: como as regras tornam o MMA mais seguro. A diferença entre arte marcial e violência. O MMA nas escolas: ensinar ou não? Respeito nas artes marciais.', ['O MMA deveria ser permitido para menores de idade? Argumente com base em saúde e ética.', 'O que diferencia artes marciais de briga de rua? Quais valores as artes marciais transmitem?']),
  createLesson('g1-ef-b4-l4', 'L4: Planejamento de Vida Ativa', 'educacao_fisica', 'Vida ativa: não é só ir à academia — é integrar movimento ao cotidiano. Vida ativa vs. exercício estruturado. Exemplos de vida ativa: ir a pé ou de bicicleta para lugares próximos, subir escadas, fazer pausas ativas no estudo, cuidar de jardim, brincar com pets. O estilo de vida sedentário moderno: trabalho e estudo em tela, deslocamento de carro, entretenimento passivo. Planejamento: como ser ativo em um mundo desenhado para o sedentarismo. Metas realistas e sustentáveis. O movimento como parte da identidade, não como obrigação.', ['Como você pode incorporar mais movimento ao seu dia sem ir necessariamente à academia?', 'Monte um "plano de vida ativa" para os próximos 3 meses que seja realista para sua rotina.']),
  createLesson('g1-ef-b4-l5', 'L5: Criatividade Corporal — Movimento Inventado', 'educacao_fisica', 'O corpo como instrumento de criação. Criatividade no movimento: improvisar, inventar, brincar com o corpo. Improviso em dança: dançar sem coreografia definida, respondendo à música e ao espaço. Criação coletiva: grupo inventa uma sequência de movimentos. Parkour: arte de superar obstáculos com o corpo. Ginástica acrobática: criar figuras em grupo. Slackline: equilíbrio e criatividade. Expressão corporal em teatro: usar o corpo para contar histórias. Por que a criatividade é uma habilidade motora? O corpo "inteligente".', ['Crie uma sequência de 10 movimentos sem nome — totalmente inventada por você.', 'O que você descobriu sobre seu corpo ao ser convidado a criar livremente?']),
  createLesson('g1-ef-b4-l6', 'L6: Avaliação Final de Aptidão Física', 'educacao_fisica', 'Avaliação final do ano: revisão de todos os testes de aptidão física. Comparação com início do ano e meio do ano: trajetória de evolução. Componentes: resistência cardiorrespiratória, força/resistência muscular, flexibilidade, composição corporal. Análise crítica: o que os testes medem? O que não medem (felicidade, sentido de pertencimento, amor pelo movimento)? Metas para o próximo ano. Além dos números: como você se sente? Você gosta de se movimentar? Isso importa mais do que qualquer teste.', ['Compare seus 3 registros de aptidão física (início, meio e fim do ano). O que mudou?', 'O que é mais importante: seus números na avaliação ou seus hábitos de movimento? Por quê?']),
  createLesson('g1-ef-b4-l7', 'L7: Projeto Final — EF na Minha Vida', 'educacao_fisica', 'Projeto final de EF da 1ª série. Cada aluno produz um portfólio reflexivo: práticas corporais que descobriu ou aprofundou no ano, impacto na saúde física e mental, valores aprendidos (fair play, cooperação, inclusão), plano de atividade física para 2025. Formato: pode ser texto, vídeo, apresentação, cartaz. Compartilhamento em sala. Celebração: a EF como componente que contribui para o desenvolvimento integral do ser humano.', ['Produza seu portfólio reflexivo de EF do ano: descobertas, crescimentos, planos.', 'Apresente para a turma: qual foi a prática corporal mais transformadora para você neste ano?']),
  createLesson('g1-ef-b4-l8', 'L8: Meditação e Atenção Plena — Aplicação', 'educacao_fisica', 'Mindfulness (atenção plena): estar presente no momento, sem julgamento. Aplicação na EF: meditação antes da prática (foco e intenção), scan corporal (consciência de cada parte do corpo), respiração consciente (regulação do sistema nervoso), meditação pós-exercício (integração). Evidências científicas: mindfulness reduz ansiedade, melhora concentração, aumenta performance esportiva. Mindfulness e ENEM: técnicas para gerenciar o estresse antes da prova. Prática guiada de meditação (10 minutos) em sala de aula.', ['Pratique a meditação guiada de 10 minutos. Como você se sentiu antes e depois?', 'Como você poderia usar técnicas de atenção plena no estudo e na prova do ENEM?']),
  createLesson('g1-ef-b4-l9', 'L9: Esporte e Cidadania Global', 'educacao_fisica', 'O esporte como linguagem universal. Esporte e paz: iniciativas esportivas em zonas de conflito. Esporte e cooperação internacional: Copa do Mundo, Olimpíadas como encontros de povos. Esporte e desenvolvimento: ONU usa esporte para cumprir os SDGs. Esporte e combate ao racismo: movimentos de atletas (BLM e o esporte). Esporte e meio ambiente: iniciativas de atletas ambientalistas. O atleta como cidadão global: responsabilidade além da quadra. Você, como praticante de atividade física, também é cidadão — o que você vai fazer com isso?', ['Como o esporte contribui para a paz e a cooperação entre países? Dê exemplos.', 'O que você, como jovem tocantinense que pratica atividade física, pode contribuir para sua comunidade?']),
  createLesson('g1-ef-b4-l10', 'L10: Revisão Final e Celebração', 'educacao_fisica', 'Última aula de Educação Física da 1ª série. Revisão dos grandes temas do ano: cultura corporal, saúde integral, esportes (coletivos, individuais, alternativos, de aventura), dança, lutas, ginástica, práticas integrativas, esporte e sociedade (política, mídia, gênero, raça, inclusão), nutrição, lesões, planejamento de AF. Grande celebration game: jogo coletivo com todas as turmas — celebração pela participação e pelo crescimento. Mensagem final: você tem um corpo capaz de muito mais do que pensa. Mova-se!', ['Participe do celebration game com entusiasmo e fair play.', 'Escreva uma mensagem para seu eu da 2ª série sobre o que a Educação Física te ensinou neste ano.']),
  createLesson('g1-ef-b4-l11', 'L11: Biomecanica Básica — O Corpo em Movimento', 'educacao_fisica', 'Biomecânica: ciência que analisa o movimento humano usando princípios da física. Conceitos básicos: força (Newtons), alavancas (classe 1, 2, 3 — o corpo é cheio de alavancas), centro de massa (equilíbrio), velocidade vs. aceleração, impulso, potência. Aplicação no esporte: como a biomecânica melhora a técnica. Arremesso do disco: princípio da rotação e liberação. Corrida: ângulo de ataque e passada. Salto: impulso e trajetória. Biomecânica e lesões: entender o movimento correto previne lesões. Análise de movimento em vídeo.', ['Analise o vídeo desta técnica esportiva usando conceitos de biomecânica.', 'Qual alavanca corporal você usa ao arremessar uma bola? Explique.']),
  createLesson('g1-ef-b4-l12', 'L12: Fisiologia do Exercício — Introdução', 'educacao_fisica', 'O que acontece no corpo durante o exercício. Sistema cardiovascular: o coração bombeia mais sangue, frequência cardíaca sobe, vasos se dilatam. Sistema respiratório: mais oxigênio, mais CO2 liberado, frequência respiratória aumenta. Sistema muscular: fibras musculares recrutadas, fadiga, produção de lactato. Termorregulação: suor e radiação de calor. Metabolismo energético: ATP → PC → glicólise anaeróbica → oxidação aeróbica. VO2 máx: capacidade máxima de usar oxigênio — indicador de aptidão cardiorrespiratória. Por que o corpo muda com o treinamento.', ['Que sensações físicas você percebe durante uma atividade intensa? Explique o que está acontecendo no corpo.', 'Por que o VO2 máx é considerado o melhor indicador de aptidão cardiorrespiratória?']),
  createLesson('g1-ef-b4-l13', 'L13: Cultura Corporal do Tocantins', 'educacao_fisica', 'Cultura corporal específica do Tocantins. Jogos indígenas: povos Karajá (corridas, nado, lutas), Xerente (corrida com tora — similar à corrida de tora dos Krahô), Javaé. Festa do Caprichosa (Palmas): competição cultural que inclui dança e performance. Balneários e praias fluviais: esportes e lazer nas margens do Araguaia e Tocantins. Pesca esportiva: o Araguaia e seus dourados. Margeado pelo Cerrado: trilhas e ecoturismo. Esporte e identidade tocantinense: ser do Tocantins tem uma cultura corporal única. Orgulho regional.', ['O que é único na cultura corporal do Tocantins? Pesquise e apresente um aspecto pouco conhecido.', 'Como a prática de atividades físicas e esportes está ligada à identidade de ser tocantinense?']),
  createLesson('g1-ef-b4-l14', 'L14: Futuro do Esporte — Tecnologia e Inovação', 'educacao_fisica', 'O esporte no futuro. VAR (Video Assistant Referee): tecnologia no árbitrio do futebol. Wearables (smartwatch, GPS, heart rate monitor): monitoramento em tempo real. IA no esporte: análise de dados, previsão de lesões, scouting. Esportes sintéticos: pistas de atletismo, grama artificial. Olimpíadas do futuro: que esportes serão incluídos? Esports: a fronteira entre jogo e esporte. Exoesqueletos: reabilitação e futura "atletização"? Bioética esportiva: doping genético, modificação do corpo. Onde o esporte vai chegar em 50 anos?', ['Como a tecnologia tem mudado o esporte que você mais acompanha?', 'Escreva um texto futurista sobre as Olimpíadas de 2076: que esportes existirão? Como serão?']),
  createLesson('g1-ef-b4-l15', 'L15: Práticas de Encerramento — EF como Estilo de Vida', 'educacao_fisica', 'Encerrando o ano com foco no futuro. EF não termina com a aula — é um estilo de vida. O que significa ser uma pessoa fisicamente ativa em 2025: não é necessariamente ir à academia todos os dias. É mover-se com frequência, com prazer, com propósito. Encontrando sua prática: que tipo de movimento te faz feliz? Que prática você consegue manter? Comprometimento: uma decisão que você toma a cada dia. Celebração final: cada aluno compartilha a prática corporal que vai continuar fazendo.', ['Qual prática corporal você vai levar para sua vida após a 1ª série? Por quê?', 'Escreva uma carta para seu eu de 30 anos: como você quer que sua vida ativa seja?']),
  createLesson('g1-ef-b4-l16', 'L16: Esporte e Raça no Brasil', 'educacao_fisica', 'A dimensão racial no esporte brasileiro. O futebol e a raça: a democratização do futebol e a ascensão de jogadores negros — e o racismo que persiste. Negros são maioria no futebol profissional mas minoria em posições de gestão. Racismo no esporte: casos recentes (Vinicius Jr., Rafael Natal). A sub-representação negra em esportes de alto custo (tênis, hipismo, vela). Política de cotas e esporte: como garantir representatividade. Representatividade importa: Rebeca Andrade como símbolo. Interseccionalidade: raça, gênero e classe no esporte.', ['O racismo no esporte é uma extensão do racismo na sociedade? Argumente.', 'Por que a representatividade de Rebeca Andrade vai além do esporte?']),
  createLesson('g1-ef-b4-l17', 'L17: Prática Livre — Autonomia Corporal', 'educacao_fisica', 'Aula de autonomia corporal: os alunos escolhem como usar a aula. Opções disponíveis: praticar o esporte preferido, explorar uma nova modalidade, dançar, meditar, fazer yoga, simplesmente jogar e brincar. Regra única: todo mundo se move, respeita os colegas e se diverte. Reflexão: o que você escolhe quando tem liberdade total? A escolha revela suas preferências e valores. Ao ter autonomia, você exerce o mais importante objetivo da EF escolar: querer se mover por conta própria.', ['O que você escolheu fazer na aula livre? O que essa escolha diz sobre você?', 'Autonomia corporal é uma habilidade que a EF escolar deveria desenvolver? Por quê?']),
  createLesson('g1-ef-b4-l18', 'L18: Encerramento do Ano', 'educacao_fisica', 'Última aula de EF da 1ª série. Momento de gratidão e celebração. Cada aluno compartilha: a prática corporal que descobriu, o maior aprendizado, como a EF impactou sua saúde. Jogo final coletivo: toda a turma reunida, brincando com regras combinadas na hora — improvisação coletiva. Mensagem do professor: você tem um corpo único. Respeite-o, cuide-o, mova-o. A saúde é seu bem mais precioso. Boa continuação na 2ª série!', ['Compartilhe: qual foi o maior aprendizado de EF neste ano?', 'Escreva uma promessa de movimento para você mesmo: o que você vai fazer na 2ª série para se manter ativo?']),
];
